const clamp = (x, a, b) => Math.max(a, Math.min(b, x));
function recoverP(r) {
  const amtPen = r.amount >= 250 ? 0.06 : r.amount >= 120 ? 0.03 : 0;
  return clamp(0.97 - r.days * 0.004 - (1 - r.onTime) * 0.30 - amtPen, 0.05, 0.97);
}
