/* ================= OPS ↔ CASHFLOW MODULE (embedded) ================= */
/* ---------- palette ---------- */
const C_OPS = {
  bg: "#0A0E18", panel: "#121A2B", panel2: "#0E1422",
  line: "rgba(255,255,255,0.08)", line2: "rgba(255,255,255,0.045)",
  txt: "#E9EDF6", sub: "#8A93AA",
  gold: "#F5B83D", goldSoft: "rgba(245,184,61,0.14)",
  green: "#37D29A", greenSoft: "rgba(55,210,154,0.12)",
  red: "#FF5269", redSoft: "rgba(255,82,105,0.13)",
  orange: "#FF9A3D", orangeSoft: "rgba(255,154,61,0.13)",
  cyan: "#54C7FF", cyanSoft: "rgba(84,199,255,0.12)",
  violet: "#A98BFF", violetSoft: "rgba(169,139,255,0.14)",
};
const MONO_OPS = "'IBM Plex Mono', ui-monospace, monospace";
const UI_OPS = "'Manrope', system-ui, sans-serif";
const DISP_OPS = "'Sora', 'Manrope', system-ui, sans-serif";

/* ---------- cash model (triệu đồng, theo tuần) ---------- */
const START_CASH_OPS = 520;
const INFLOW_OPS  = [165, 158, 172, 150, 168, 160, 152, 175, 158, 166, 162, 170, 175];
const OUTFLOW_OPS = [190, 145, 230, 340, 195, 400, 215, 345, 195, 150, 145, 350, 195];
const OUT_NOTES_OPS = { 0: "note.rent", 2: "note.vat", 3: "note.salary1", 5: "note.supplier", 6: "note.cit", 7: "note.salary2", 11: "note.salary3" };
const DAYS_PER_WEEK_OPS = 7;

/* ---------- inventory ---------- */
const SUPPLIERS_OPS = {
  s1: { id: "s1", name: "Cty TNHH Phú Thành", lead: 4, reliab: 0.97, price: 1.0,  terms: 0 },  // terms = số tuần được trả chậm
  s2: { id: "s2", name: "Đại Nam Logistics",  lead: 3, reliab: 0.93, price: 1.06, terms: 2 },
  s3: { id: "s3", name: "Tân Á Industrial",   lead: 6, reliab: 0.99, price: 0.94, terms: 4 },
};
const INIT_SKUS_OPS = [
  { id: "SKU-A12", name: "ops.sku.A12",   cat: "Nguyên liệu", stock: 92,  reorder: 80,  max: 320, demand: 14, trend: 0.20, cost: 0.42, sup: "s1" },
  { id: "SKU-C33", name: "ops.sku.C33",   cat: "Bao bì",      stock: 138, reorder: 120, max: 500, demand: 24, trend: 0.30, cost: 0.18, sup: "s3" },
  { id: "SKU-E20", name: "ops.sku.E20", cat: "Nguyên liệu", stock: 118, reorder: 100, max: 360, demand: 13, trend: 0.18, cost: 0.36, sup: "s2" },
  { id: "SKU-D51", name: "ops.sku.D51",    cat: "Phụ gia",     stock: 70,  reorder: 45,  max: 180, demand: 6,  trend: 0.05, cost: 0.88, sup: "s1" },
];

const clamp_OPS = (x, a, b) => Math.max(a, Math.min(b, x));
const fmtVnd_OPS = (m) => `${Math.round(m * 1e6).toLocaleString("vi-VN")} ₫`;
const fmtTr_OPS = (m) => `${Math.round(m).toLocaleString("vi-VN")} tr`;
const runRate_OPS = (s) => Math.max(1, s.demand * (1 + Math.max(0, s.trend)));
const daysCover_OPS = (s) => Math.floor(s.stock / runRate_OPS(s));
function orderQty_OPS(s) { const safety = Math.ceil(runRate_OPS(s) * DAYS_PER_WEEK_OPS * SUPPLIERS_OPS[s.sup].lead / 7 * 1.2); return Math.max(0, s.max - s.stock + safety); }

/* ---------- cash-flow forecast_OPS given committed POs ---------- */
function forecast_OPS(committedPOs, extraPO) {
  const all = extraPO ? [...committedPOs, extraPO] : committedPOs;
  const outAdd = Array(13).fill(0);
  all.forEach((p) => { if (p.payWeek >= 0 && p.payWeek < 13) outAdd[p.payWeek] += p.cost; });
  const series = []; let bal = START_CASH_OPS; let minBal = Infinity, minWeek = 0; let firstNeg = -1;
  for (let i = 0; i < 13; i++) {
    bal += INFLOW_OPS[i] - OUTFLOW_OPS[i] - outAdd[i];
    series.push({ name: `T${i + 1}`, idx: i, bal: Math.round(bal), poOut: outAdd[i] });
    if (bal < minBal) { minBal = bal; minWeek = i; }
    if (bal < 0 && firstNeg < 0) firstNeg = i;
  }
  return { series, minBal: Math.round(minBal), minWeek, firstNeg };
}

/* ---------- the dual-check decision engine ---------- */
/* Given a SKU needing reorder, build the ideal PO then test cash impact and
   pick a balancing strategy if it would push cash negative. */
const SAFETY_FLOOR_OPS = 40; // quỹ tối thiểu muốn giữ (tr)
function decide_OPS(sku, currentWeek, committedPOs) {
  const sup = SUPPLIERS_OPS[sku.sup];
  const qty = orderQty_OPS(sku);
  const fullCost = qty * sku.cost * sup.price;
  const payWeek = currentWeek + sup.terms; // trả khi tới hạn theo điều khoản NCC

  const mkPO = (q, pw, tag) => ({ id: "PO-" + (1000 + Math.floor(Math.random() * 9000)), skuId: sku.id, qty: q, supId: sku.sup, cost: q * sku.cost * sup.price, payWeek: pw, arriveWeek: currentWeek + Math.ceil(sup.lead / 7) + 1, strategy: tag });

  const ideal = mkPO(qty, payWeek, "full");
  const base = forecast_OPS(committedPOs);
  const withIdeal = forecast_OPS(committedPOs, ideal);
  const safe = withIdeal.minBal >= SAFETY_FLOOR_OPS;

  // candidate strategies if not safe
  const strategies = [];
  strategies.push({ key: "full", icon: Send, lkey: "ops.strat.full", po: ideal, ...withIdeal });

  // delay payment to a later, less-stressed week (push to safest trough+1)
  const delayWeek = clamp_OPS(base.minWeek + 1, currentWeek, 12);
  const delayed = mkPO(qty, delayWeek, "delay");
  strategies.push({ key: "delay", icon: Calendar, lkey: "ops.strat.delay", lvars: { w: delayWeek + 1 }, po: delayed, ...forecast_OPS(committedPOs, delayed) });

  // split order: 60% now, 40% deferred 3 weeks
  const q1 = Math.round(qty * 0.6);
  const splitNow = mkPO(q1, payWeek, "split");
  const splitFc = forecast_OPS(committedPOs, splitNow);
  strategies.push({ key: "split", icon: Scissors, lkey: "ops.strat.split", lvars: { q1, qty }, po: splitNow, ...splitFc, nkey: "ops.strat.splitNote", nvars: { rest: qty - q1 } });

  // negotiate longer terms with the most lenient supplier (s3)
  const altSup = SUPPLIERS_OPS.s3;
  const negPay = currentWeek + altSup.terms;
  const negCost = qty * sku.cost * altSup.price;
  const negPO = { id: "PO-" + (1000 + Math.floor(Math.random() * 9000)), skuId: sku.id, qty, supId: "s3", cost: negCost, payWeek: negPay, arriveWeek: currentWeek + Math.ceil(altSup.lead / 7) + 1, strategy: "negotiate" };
  strategies.push({ key: "negotiate", icon: Handshake, lkey: "ops.strat.negotiate", lvars: { w: altSup.terms }, po: negPO, ...forecast_OPS(committedPOs, negPO) });

  // choose: prefer safe strategies; among safe, the one with highest minBal & soonest stock
  const ranked = [...strategies].map((st) => ({ ...st, ok: st.minBal >= SAFETY_FLOOR_OPS }))
    .sort((a, b) => (b.ok - a.ok) || (b.minBal - a.minBal));
  const chosen = ranked[0];

  return { sku, sup, qty, fullCost, ideal, base, withIdeal, safe, strategies: ranked, chosen };
}

const STEP_LABELS_OPS = [
  { k: "detect", icon: AlertTriangle, lkey: "ops.step.detect", c: C_OPS.red },
  { k: "po", icon: FileText, lkey: "ops.step.po", c: C_OPS.gold },
  { k: "cash", icon: Wallet, lkey: "ops.step.cash", c: C_OPS.cyan },
  { k: "balance", icon: Scale, lkey: "ops.step.balance", c: C_OPS.violet },
  { k: "await", icon: ShieldCheck, lkey: "ops.step.await", c: C_OPS.green },
];

function OpsCashflow() {
  const { t } = useT();
  const [skus, setSkus] = useState(INIT_SKUS_OPS);
  const [week, setWeek] = useState(0);
  const [auto, setAuto] = useState(false);
  const [log, setLog] = useState([{ t: 0, type: "sys", key: "ops.log.boot" }]);
  const [mission, setMission] = useState(null);
  const [step, setStep] = useState(-1);
  const [chosenKey, setChosenKey] = useState(null);
  const [committed, setCommitted] = useState([]); // approved POs feeding the forecast_OPS
  const handled = useRef(new Set());

  useEffect(() => {
    const l = document.createElement("link"); l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Sora:wght@600;700;800&family=IBM+Plex+Mono:wght@400;500;600&display=swap";
    document.head.appendChild(l); return () => { document.head.removeChild(l); };
  }, []);

  const pushLog = (type, key, vars) => setLog((L) => [{ t: Date.now() + Math.random(), type, key, vars, week }, ...L].slice(0, 30));
  const stratLabel = (st) => st.lkey ? t(st.lkey, st.lvars) : st.label;
  const resolveVars = (vars) => {
    if (!vars) return vars;
    return Object.fromEntries(Object.entries(vars).map(([k, v]) =>
      [k, v && typeof v === "object" && "$key" in v ? t(v.$key, resolveVars(v.$vars)) : v]
    ));
  };

  const liveForecast = useMemo(() => forecast_OPS(committed), [committed]);
  const previewForecast = useMemo(() => {
    if (!mission || step < 2) return null;
    const st = mission.strategies.find((s) => s.key === chosenKey) || mission.chosen;
    return { fc: st, base: mission.base };
  }, [mission, step, chosenKey]);

  const tick = () => {
    setWeek((w) => w + 1);
    setSkus((prev) => prev.map((s) => {
      const consume = Math.round(runRate_OPS(s) * DAYS_PER_WEEK_OPS * (0.85 + Math.random() * 0.3) / 7 * 7 / 7);
      const weeklyConsume = Math.round(runRate_OPS(s) * (0.85 + Math.random() * 0.3));
      let stock = Math.max(0, s.stock - weeklyConsume);
      const incoming = committed.filter((p) => p.skuId === s.id && p.arriveWeek === week + 1);
      incoming.forEach((p) => { stock += p.qty; });
      const trend = clamp_OPS(s.trend + (Math.random() - 0.45) * 0.05, -0.1, 0.45);
      return { ...s, stock, trend };
    }));
  };

  useEffect(() => {
    if (mission) return;
    const risk = skus.find((s) => s.stock <= s.reorder && s.trend > 0.02 && !handled.current.has(s.id + ":" + week));
    if (risk) start(risk);
    // eslint-disable-next-line
  }, [skus, week]);

  useEffect(() => {
    if (!auto) return;
    const id = setInterval(() => { if (!mission) tick(); }, 1700);
    return () => clearInterval(id);
    // eslint-disable-next-line
  }, [auto, mission, week, committed]);

  useEffect(() => {
    const arr = committed.filter((p) => p.arriveWeek === week);
    arr.forEach((p) => pushLog("ok", "ops.log.arrive", { qty: p.qty, sku: p.skuId }));
    // eslint-disable-next-line
  }, [week]);

  function start(s) {
    handled.current.add(s.id + ":" + week);
    const d = decide_OPS(s, week, committed);
    setMission(d); setStep(0); setChosenKey(d.chosen.key);
    pushLog("agent", "ops.log.start", { sku: s.id, stock: s.stock, reorder: s.reorder, p: Math.round(s.trend * 100) });
  }

  useEffect(() => {
    if (!mission || step < 0 || step >= STEP_LABELS_OPS.length - 1) return;
    const logs = {
      0: () => pushLog("agent", "ops.log.s0", { name: { $key: mission.sku.name }, d: daysCover_OPS(mission.sku) }),
      1: () => pushLog("agent", "ops.log.s1", { qty: mission.qty, sup: mission.sup.name, cost: fmtTr_OPS(mission.fullCost) }),
      2: () => pushLog("agent", mission.safe ? "ops.log.s2safe" : "ops.log.s2risk",
        mission.safe ? undefined : { min: fmtTr_OPS(mission.withIdeal.minBal), neg: mission.withIdeal.firstNeg >= 0 ? { $key: "ops.log.s2neg", $vars: { w: mission.withIdeal.firstNeg + 1 } } : "" }),
      3: () => pushLog(mission.safe ? "agent" : "warn", mission.safe ? "ops.log.s3safe" : "ops.log.s3conflict",
        mission.safe ? undefined : { label: { $key: mission.chosen.lkey, $vars: mission.chosen.lvars }, min: fmtTr_OPS(mission.chosen.minBal) }),
    };
    const tid = setTimeout(() => { logs[step]?.(); setStep((x) => x + 1); }, 1150);
    return () => clearTimeout(tid);
    // eslint-disable-next-line
  }, [mission, step]);

  useEffect(() => {
    if (!auto || !mission || step < STEP_LABELS_OPS.length - 1) return;
    const tid = setTimeout(() => approve(), 1200);
    return () => clearTimeout(tid);
    // eslint-disable-next-line
  }, [auto, mission, step]);

  function approve() {
    const st = mission.strategies.find((s) => s.key === chosenKey) || mission.chosen;
    setCommitted((P) => [...P, st.po]);
    pushLog("ok", "ops.log.approve", { id: st.po.id, label: { $key: st.lkey, $vars: st.lvars }, cost: fmtTr_OPS(st.po.cost), payW: st.po.payWeek + 1, arrW: st.po.arriveWeek + 1 });
    setMission(null); setStep(-1); setChosenKey(null);
  }
  function reject() { pushLog("warn", "ops.log.reject", { sku: mission.sku.id }); setMission(null); setStep(-1); setChosenKey(null); }
  function reset() {
    setSkus(INIT_SKUS_OPS); setWeek(0); setAuto(false); setMission(null); setStep(-1); setChosenKey(null);
    setCommitted([]); handled.current = new Set();
    setLog([{ t: 0, type: "sys", key: "ops.log.reset" }]);
  }

  const atRisk = skus.filter((s) => s.stock <= s.reorder).length;
  const rk = liveForecast.minBal < 0 ? C_OPS.red : liveForecast.minBal < SAFETY_FLOOR_OPS ? C_OPS.orange : C_OPS.green;

  // chart data: live + optional preview overlay
  const chartData = useMemo(() => {
    return liveForecast.series.map((d, i) => ({
      ...d,
      preview: previewForecast ? previewForecast.fc.series[i].bal : null,
      ideal: (mission && step >= 2) ? mission.withIdeal.series[i].bal : null,
    }));
  }, [liveForecast, previewForecast, mission, step]);
  const yMin = Math.min(0, ...chartData.map((d) => Math.min(d.bal, d.preview ?? 999, d.ideal ?? 999)));
  const yMax = Math.max(START_CASH_OPS, ...chartData.map((d) => d.bal));

  return (
    <div style={{ fontFamily: UI_OPS, color: C_OPS.txt }}>
      <style>{`
        *{box-sizing:border-box}
        @keyframes rise{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.45}}
        @keyframes slideL{from{opacity:0;transform:translateX(12px)}to{opacity:1;transform:none}}
        .card{animation:rise .5s cubic-bezier(.2,.7,.3,1) both}
        .tnum{font-family:${MONO_OPS};font-variant-numeric:tabular-nums}
        .btn{cursor:pointer;transition:all .15s;border:none;font-family:${UI_OPS}}
        .btn:hover{filter:brightness(1.1)}
        .live{animation:pulse 1.6s ease-in-out infinite}
        .logitem{animation:slideL .35s ease both}
        ::-webkit-scrollbar{height:8px;width:8px}::-webkit-scrollbar-thumb{background:rgba(255,255,255,.12);border-radius:8px}
      `}</style>

      <div style={{ maxWidth: 1280, margin: "0 auto" }}>
        {/* HEADER */}
        <header style={{ display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", justifyContent: "space-between", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
            <div style={{ display: "flex" }}>
              <div style={{ width: 40, height: 40, borderRadius: 11, display: "grid", placeItems: "center", background: `linear-gradient(135deg, ${C_OPS.gold}, #C9892A)`, zIndex: 2 }}><Boxes size={20} color="#1a1206" strokeWidth={2.3} /></div>
              <div style={{ width: 40, height: 40, borderRadius: 11, display: "grid", placeItems: "center", background: `linear-gradient(135deg, ${C_OPS.cyan}, #2E9BD6)`, marginLeft: -10 }}><Wallet size={20} color="#06202f" strokeWidth={2.3} /></div>
            </div>
            <div>
              <div style={{ fontFamily: DISP_OPS, fontWeight: 800, fontSize: 18.5, letterSpacing: "-0.02em" }}>{t("ops.title")}</div>
              <div style={{ fontSize: 12.3, color: C_OPS.sub, marginTop: 1 }}>{t("ops.subtitle1")} <b style={{ color: C_OPS.violet }}>{t("ops.subtitle.and")}</b> {t("ops.subtitle2")}</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 9, flexWrap: "wrap", alignItems: "center" }}>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 7, fontSize: 12.3, fontWeight: 700, padding: "8px 13px", borderRadius: 10, color: auto ? C_OPS.green : C_OPS.sub, background: auto ? C_OPS.greenSoft : "rgba(255,255,255,.04)", border: `1px solid ${auto ? C_OPS.green + "55" : C_OPS.line}` }}><span className={auto ? "live" : ""} style={{ width: 8, height: 8, borderRadius: 9, background: auto ? C_OPS.green : C_OPS.sub }} />{auto ? t("ops.auto") : t("ops.paused")}</span>
            <span className="tnum" style={{ fontSize: 12.3, fontWeight: 700, padding: "8px 13px", borderRadius: 10, color: C_OPS.gold, background: C_OPS.goldSoft, border: `1px solid ${C_OPS.gold}33` }}>{t("ops.weekN", { n: week + 1 })}</span>
          </div>
        </header>

        {/* CONTROLS */}
        <div className="card" style={{ ...panel, padding: "12px 16px", marginBottom: 16, display: "flex", gap: 12, flexWrap: "wrap", alignItems: "center" }}>
          <button className="btn" onClick={tick} disabled={!!mission} style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "9px 16px", borderRadius: 10, fontWeight: 800, fontSize: 13, color: "#1a1206", background: mission ? "#33415544" : `linear-gradient(135deg, ${C_OPS.gold}, #C9892A)`, opacity: mission ? .5 : 1, cursor: mission ? "not-allowed" : "pointer" }}><ChevronRight size={16} />{t("ops.fastForward")}</button>
          <button className="btn" onClick={() => setAuto((a) => !a)} style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "9px 16px", borderRadius: 10, fontWeight: 700, fontSize: 13, color: C_OPS.txt, background: "rgba(255,255,255,.05)", border: `1px solid ${C_OPS.line}` }}>{auto ? <Pause size={15} /> : <Play size={15} />}{auto ? t("ops.stop") : t("ops.runAuto")}</button>
          <div style={{ marginLeft: "auto", display: "flex", gap: 16, alignItems: "center" }}>
            <Mini_OPS label={t("ops.mini.atRisk")} value={atRisk} c={atRisk ? C_OPS.red : C_OPS.green} />
            <Mini_OPS label={t("ops.mini.trough")} value={fmtTr_OPS(liveForecast.minBal)} c={rk} />
            <Mini_OPS label={t("ops.mini.po")} value={committed.length} c={C_OPS.cyan} />
            <button className="btn" onClick={reset} title={t("ops.reset")} style={{ display: "grid", placeItems: "center", width: 36, height: 36, borderRadius: 9, color: C_OPS.sub, background: "rgba(255,255,255,.05)", border: `1px solid ${C_OPS.line}` }}><RotateCcw size={15} /></button>
          </div>
        </div>

        <div style={{ display: "grid", gap: 16, gridTemplateColumns: "minmax(0,1fr) minmax(0,1.05fr)" }}>
          {/* LEFT: cashflow chart + inventory */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <section className="card" style={panelOps}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", flexWrap: "wrap", gap: 8 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}><Wallet size={17} color={C_OPS.cyan} /><h3 style={h3Ops}>{t("ops.chart.title")}</h3></div>
                <div style={{ display: "flex", gap: 13, fontSize: 11.5, color: C_OPS.sub }}>
                  <Lg_OPS c={C_OPS.cyan} label={t("ops.lg.now")} />
                  {mission && step >= 2 && <Lg_OPS c={C_OPS.red} dash label={t("ops.lg.full")} />}
                  {previewForecast && <Lg_OPS c={C_OPS.violet} label={t("ops.lg.balanced")} />}
                </div>
              </div>
              <div style={{ fontSize: 12.2, color: C_OPS.sub, margin: "4px 0 6px" }}>{t("ops.chart.unit")}</div>
              <div style={{ height: 250, marginLeft: -12 }}>
                <ResponsiveContainer width="100%" height="100%">
                  <ComposedChart data={chartData} margin={{ top: 8, right: 12, bottom: 2, left: 2 }}>
                    <defs><linearGradient id="gBal" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={C_OPS.cyan} stopOpacity={0.3} /><stop offset="100%" stopColor={C_OPS.cyan} stopOpacity={0.03} /></linearGradient></defs>
                    <CartesianGrid stroke={C_OPS.line2} vertical={false} />
                    <XAxis dataKey="name" tick={{ fill: C_OPS.sub, fontSize: 11, fontFamily: MONO_OPS }} axisLine={{ stroke: C_OPS.line }} tickLine={false} />
                    <YAxis tickFormatter={(v) => Math.round(v).toLocaleString("vi-VN")} tick={{ fill: C_OPS.sub, fontSize: 11, fontFamily: MONO_OPS }} axisLine={false} tickLine={false} width={44} domain={[Math.floor(yMin * 1.1), Math.ceil(yMax * 1.05)]} />
                    <Tooltip content={<TipBox_OPS />} cursor={{ stroke: C_OPS.line }} />
                    <ReferenceLine y={0} stroke={C_OPS.red} strokeWidth={1.4} strokeDasharray="2 3" />
                    <ReferenceLine y={SAFETY_FLOOR_OPS} stroke={C_OPS.orange} strokeWidth={1} strokeDasharray="3 4" />
                    <Area type="monotone" dataKey="bal" stroke={C_OPS.cyan} strokeWidth={2.6} fill="url(#gBal)" dot={false} activeDot={{ r: 4, fill: C_OPS.cyan }} animationDuration={450} />
                    {mission && step >= 2 && <Line type="monotone" dataKey="ideal" stroke={C_OPS.red} strokeWidth={1.6} strokeDasharray="5 4" dot={false} animationDuration={450} />}
                    {previewForecast && <Line type="monotone" dataKey="preview" stroke={C_OPS.violet} strokeWidth={2.4} dot={false} animationDuration={450} />}
                    {liveForecast.firstNeg >= 0 && <ReferenceDot x={chartData[liveForecast.firstNeg].name} y={liveForecast.series[liveForecast.firstNeg].bal} r={4.5} fill={C_OPS.red} stroke="#fff" strokeWidth={1.4} />}
                  </ComposedChart>
                </ResponsiveContainer>
              </div>
            </section>

            <section className="card" style={panelOps}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}><Boxes size={17} color={C_OPS.gold} /><h3 style={h3Ops}>{t("ops.inv.title")}</h3></div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {skus.map((s) => {
                  const p = clamp_OPS(s.stock / s.max, 0, 1); const low = s.stock <= s.reorder;
                  const barC = low ? C_OPS.red : p < 0.45 ? C_OPS.gold : C_OPS.green; const active = mission?.sku.id === s.id;
                  return (
                    <div key={s.id} style={{ padding: "10px 12px", borderRadius: 12, background: active ? C_OPS.violetSoft : C_OPS.panel2, border: `1px solid ${active ? C_OPS.violet + "77" : low ? C_OPS.red + "44" : C_OPS.line}`, transition: "all .3s" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
                        <div style={{ minWidth: 0 }}>
                          <div style={{ display: "flex", gap: 7, alignItems: "center" }}><span className="tnum" style={{ fontSize: 11, color: C_OPS.sub }}>{s.id}</span><span style={{ fontWeight: 700, fontSize: 12.5, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{t(s.name)}</span></div>
                          <div style={{ fontSize: 10.8, color: C_OPS.sub, marginTop: 2, display: "flex", gap: 9 }}>
                            <span style={{ color: s.trend > 0.02 ? C_OPS.orange : C_OPS.sub, display: "inline-flex", alignItems: "center", gap: 3 }}>{s.trend > 0.02 && <TrendingUp size={11} />}{t("ops.demand", { p: Math.round(s.trend * 100) })}</span>
                            <span className="tnum">{t("ops.daysLeft", { d: daysCover_OPS(s) })}</span>
                          </div>
                        </div>
                        <div style={{ textAlign: "right", flex: "0 0 auto" }}><span className="tnum" style={{ fontWeight: 800, fontSize: 14, color: barC }}>{s.stock}</span><span className="tnum" style={{ fontSize: 10, color: C_OPS.sub }}>/{s.max}</span></div>
                      </div>
                      <div style={{ position: "relative", height: 7, borderRadius: 5, background: "rgba(255,255,255,.07)", marginTop: 8, overflow: "hidden" }}>
                        <div style={{ width: `${p * 100}%`, height: "100%", background: barC, borderRadius: 5, transition: "width .5s" }} />
                        <div style={{ position: "absolute", top: -2, bottom: -2, left: `${clamp_OPS(s.reorder / s.max, 0, 1) * 100}%`, width: 2, background: "#fff", opacity: .6 }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>
          </div>

          {/* RIGHT: agent workflow + log */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <section className="card" style={{ ...panel, borderColor: mission ? C_OPS.violet + "55" : C_OPS.line }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                <Cpu size={17} color={C_OPS.violet} /><h3 style={h3Ops}>{t("ops.decision")}</h3>
                {mission && <span className="live tnum" style={{ marginLeft: "auto", fontSize: 11, fontWeight: 800, color: C_OPS.violet, background: C_OPS.violetSoft, padding: "3px 9px", borderRadius: 20 }}>● {t("ops.running")}</span>}
              </div>

              {!mission ? (
                <div style={{ padding: "26px 14px", textAlign: "center", color: C_OPS.sub }}>
                  <Scale size={28} color={C_OPS.sub} style={{ opacity: .5 }} />
                  <div style={{ fontSize: 12.8, marginTop: 9, lineHeight: 1.6 }}>{t("ops.idle1")} <b style={{ color: C_OPS.gold }}>{t("ops.idle.btn")}</b> {t("ops.idle2")} <b style={{ color: C_OPS.cyan }}>{t("ops.idle.cash")}</b> {t("ops.idle3")}</div>
                </div>
              ) : (
                <>
                  {/* steps */}
                  <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 4 }}>
                    {STEP_LABELS_OPS.map((st, i) => {
                      const done = i < step, cur = i === step; const Ic = st.icon;
                      return (
                        <div key={st.k} style={{ display: "flex", alignItems: "center", gap: 10, padding: "7px 9px", borderRadius: 9, background: cur ? st.c + "1c" : "transparent", border: `1px solid ${cur ? st.c + "55" : "transparent"}`, opacity: i > step ? .4 : 1, transition: "all .3s" }}>
                          <div className={cur ? "live" : ""} style={{ width: 24, height: 24, borderRadius: 7, flex: "0 0 auto", display: "grid", placeItems: "center", background: done ? C_OPS.green + "22" : st.c + "22" }}>{done ? <CheckCircle2 size={14} color={C_OPS.green} /> : <Ic size={14} color={st.c} />}</div>
                          <span style={{ fontSize: 12.5, fontWeight: cur ? 700 : 600, color: cur ? C_OPS.txt : C_OPS.sub }}>{t(st.lkey)}</span>
                          {cur && <Clock size={12} color={st.c} className="live" style={{ marginLeft: "auto" }} />}
                        </div>
                      );
                    })}
                  </div>

                  {/* PO summary */}
                  {step >= 1 && (
                    <div className="logitem" style={{ marginTop: 8, padding: "11px 13px", borderRadius: 12, background: C_OPS.panel2, border: `1px solid ${C_OPS.gold}44` }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 7 }}>
                        <span style={{ display: "inline-flex", alignItems: "center", gap: 6, fontWeight: 800, fontSize: 12.5, color: C_OPS.gold }}><FileText size={14} />{t("ops.poSuggest")} · {mission.sku.id}</span>
                        <span className="tnum" style={{ fontSize: 12, fontWeight: 800 }}>{fmtTr_OPS(mission.fullCost)}</span>
                      </div>
                      <div style={{ fontSize: 11.5, color: C_OPS.sub }}>{t("ops.poFrom", { qty: mission.qty, sup: mission.sup.name, lead: mission.sup.lead })}</div>
                    </div>
                  )}

                  {/* cash verdict */}
                  {step >= 3 && (
                    <div className="logitem" style={{ marginTop: 10, padding: "12px 14px", borderRadius: 12, background: mission.safe ? C_OPS.greenSoft : C_OPS.redSoft, border: `1px solid ${mission.safe ? C_OPS.green : C_OPS.red}55` }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 8, fontWeight: 800, fontSize: 13, color: mission.safe ? C_OPS.green : C_OPS.red, marginBottom: 4 }}>
                        {mission.safe ? <CheckCircle2 size={15} /> : <AlertTriangle size={15} />}
                        {mission.safe ? t("ops.safe") : t("ops.conflict")}
                      </div>
                      <div style={{ fontSize: 11.8, color: C_OPS.sub, lineHeight: 1.5 }}>
                        {mission.safe
                          ? t("ops.safeText", { min: fmtTr_OPS(mission.withIdeal.minBal), floor: SAFETY_FLOOR_OPS })
                          : <>{t("ops.conflictText1")} <b className="tnum" style={{ color: C_OPS.red }}>{fmtTr_OPS(mission.withIdeal.minBal)}</b>{mission.withIdeal.firstNeg >= 0 && <> {t("ops.conflictNeg", { w: mission.withIdeal.firstNeg + 1 })}</>}{t("ops.conflictText2")}</>}
                      </div>
                    </div>
                  )}

                  {/* strategy options when not safe */}
                  {step >= 3 && !mission.safe && (
                    <div style={{ marginTop: 10, display: "flex", flexDirection: "column", gap: 7 }}>
                      {mission.strategies.map((st) => {
                        const sel = st.key === chosenKey; const Ic = st.icon; const okC = st.minBal >= SAFETY_FLOOR_OPS ? C_OPS.green : st.minBal >= 0 ? C_OPS.orange : C_OPS.red;
                        return (
                          <button key={st.key} className="btn" onClick={() => setChosenKey(st.key)} style={{ textAlign: "left", display: "flex", gap: 9, alignItems: "center", padding: "10px 11px", borderRadius: 11, background: sel ? C_OPS.violetSoft : C_OPS.panel2, border: `1px solid ${sel ? C_OPS.violet + "77" : C_OPS.line}` }}>
                            <div style={{ width: 28, height: 28, borderRadius: 8, flex: "0 0 auto", display: "grid", placeItems: "center", background: sel ? C_OPS.violet + "26" : "rgba(255,255,255,.05)" }}><Ic size={14} color={sel ? C_OPS.violet : C_OPS.sub} /></div>
                            <div style={{ flex: 1, minWidth: 0 }}>
                              <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                                <span style={{ fontSize: 12.3, fontWeight: 700, flex: 1, minWidth: 0 }}>{stratLabel(st)}</span>
                                {st.key === mission.chosen.key && <span style={{ flex: "0 0 auto", fontSize: 9, fontWeight: 800, color: C_OPS.violet, background: C_OPS.violetSoft, padding: "2px 7px", borderRadius: 5, whiteSpace: "nowrap" }}>{t("ops.aiPick")}</span>}
                              </div>
                              {st.note && <div style={{ fontSize: 10.5, color: C_OPS.sub, marginTop: 2 }}>{st.note}</div>}
                              {st.nkey && <div style={{ fontSize: 10.5, color: C_OPS.sub, marginTop: 2 }}>{t(st.nkey, st.nvars)}</div>}
                            </div>
                            <div style={{ textAlign: "right", flex: "0 0 auto" }}>
                              <div className="tnum" style={{ fontSize: 12, fontWeight: 800, color: okC }}>{fmtTr_OPS(st.minBal)}</div>
                              <div style={{ fontSize: 9.5, color: C_OPS.sub }}>{t("ops.trough")}</div>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  )}

                  {/* approval */}
                  {step >= STEP_LABELS_OPS.length - 1 && (
                    <div style={{ marginTop: 12, display: "flex", gap: 9 }}>
                      <button className="btn" onClick={approve} style={{ flex: 1, display: "inline-flex", justifyContent: "center", alignItems: "center", gap: 7, padding: "11px", borderRadius: 11, fontWeight: 800, fontSize: 13.5, color: "#0b1a10", background: `linear-gradient(135deg, ${C_OPS.green}, #1FA877)` }}><Send size={15} />{t("ops.approve")}</button>
                      <button className="btn" onClick={reject} style={{ padding: "11px 16px", borderRadius: 11, fontWeight: 700, fontSize: 13, color: C_OPS.red, background: C_OPS.redSoft, border: `1px solid ${C_OPS.red}44` }}>{t("ops.reject")}</button>
                    </div>
                  )}
                </>
              )}
            </section>

            <section className="card" style={{ ...panel, flex: 1 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}><Activity size={16} color={C_OPS.cyan} /><h3 style={{ ...h3, fontSize: 15 }}>{t("ops.logTitle")}</h3></div>
              <div style={{ display: "flex", flexDirection: "column", gap: 7, maxHeight: 220, overflowY: "auto", paddingRight: 4 }}>
                {log.map((e) => {
                  const col = e.type === "agent" ? C_OPS.violet : e.type === "ok" ? C_OPS.green : e.type === "warn" ? C_OPS.red : C_OPS.sub;
                  const Ic = e.type === "agent" ? Sparkles : e.type === "ok" ? CheckCircle2 : e.type === "warn" ? AlertTriangle : Cpu;
                  return (
                    <div key={e.t} className="logitem" style={{ display: "flex", gap: 9, alignItems: "flex-start", fontSize: 11.8, lineHeight: 1.45 }}>
                      <Ic size={13} color={col} style={{ flex: "0 0 auto", marginTop: 2 }} />
                      <div><span>{t(e.key, resolveVars(e.vars))}</span>{e.week != null && <span className="tnum" style={{ color: C_OPS.sub, marginLeft: 6, fontSize: 10 }}>{t("ops.weekShort")}{e.week + 1}</span>}</div>
                    </div>
                  );
                })}
              </div>
            </section>
          </div>
        </div>

        <footer style={{ marginTop: 18, fontSize: 11.5, color: C_OPS.sub, textAlign: "center", lineHeight: 1.6 }}>
          {t("ops.footer", { floor: SAFETY_FLOOR_OPS })}
        </footer>
      </div>
    </div>
  );
}

/* ---------- sub components ---------- */
const panelOps = { background: C_OPS.panel, border: `1px solid ${C_OPS.line}`, borderRadius: 18, padding: "16px 18px 14px", boxShadow: "0 18px 40px -28px rgba(0,0,0,.7)" };
const h3Ops = { margin: 0, fontFamily: DISP_OPS, fontWeight: 700, fontSize: 15.5, letterSpacing: "-0.01em", color: C_OPS.txt };
function Mini_OPS({ label, value, c }) { return <div style={{ textAlign: "right" }}><div className="tnum" style={{ fontSize: 14.5, fontWeight: 800, color: c, lineHeight: 1.1 }}>{value}</div><div style={{ fontSize: 10.3, color: C_OPS.sub }}>{label}</div></div>; }
function Lg_OPS({ c, label, dash }) { return <span style={{ display: "inline-flex", alignItems: "center", gap: 5 }}><span style={{ width: 15, borderTop: `${dash ? "2px dashed" : "3px solid"} ${c}` }} />{label}</span>; }
function TipBox_OPS({ active, payload }) {
  const { t } = useT();
  if (!active || !payload || !payload.length) return null; const d = payload[0].payload;
  return (
    <div style={{ background: "#0A0F1C", border: `1px solid ${C_OPS.line}`, borderRadius: 12, padding: "10px 12px", fontFamily: UI_OPS, boxShadow: "0 14px 30px rgba(0,0,0,.5)", minWidth: 170 }}>
      <div style={{ fontWeight: 800, fontSize: 12.5 }}>{t("cf.week")} {d.idx + 1}</div>
      <Row_OPS k={t("ops.tip.bal")} v={fmtVnd_OPS(d.bal)} c={d.bal < 0 ? C_OPS.red : C_OPS.cyan} />
      {d.ideal != null && <Row_OPS k={t("ops.tip.full")} v={fmtVnd_OPS(d.ideal)} c={d.ideal < 0 ? C_OPS.red : C_OPS.sub} />}
      {d.preview != null && <Row_OPS k={t("ops.tip.balanced")} v={fmtVnd_OPS(d.preview)} c={C_OPS.violet} />}
      {d.poOut > 0 && <Row_OPS k={t("ops.tip.poOut")} v={`−${fmtTr_OPS(d.poOut)}`} c={C_OPS.orange} />}
      {OUT_NOTES_OPS[d.idx] && <div style={{ fontSize: 10.5, color: C_OPS.sub, marginTop: 5 }}>★ {t(OUT_NOTES_OPS[d.idx])}</div>}
    </div>
  );
}
function Row_OPS({ k, v, c }) { return <div style={{ display: "flex", justifyContent: "space-between", gap: 16, fontSize: 11.5, marginTop: 4 }}><span style={{ color: C_OPS.sub }}>{k}</span><span className="tnum" style={{ color: c, fontWeight: 700 }}>{v}</span></div>; }


/* ================= NHẮC NỢ TỰ ĐỘNG MODULE (embedded) ================= */
const C_COL = {
  bg: "#0A0E18", panel: "#121A2B", panel2: "#0E1422",
  line: "rgba(255,255,255,0.08)", line2: "rgba(255,255,255,0.045)",
  txt: "#E9EDF6", sub: "#8A93AA",
  gold: "#F5B83D", goldSoft: "rgba(245,184,61,0.14)",
  green: "#37D29A", greenSoft: "rgba(55,210,154,0.12)",
  red: "#FF5269", redSoft: "rgba(255,82,105,0.13)",
  orange: "#FF9A3D", orangeSoft: "rgba(255,154,61,0.13)",
  cyan: "#54C7FF", cyanSoft: "rgba(84,199,255,0.12)",
  violet: "#A98BFF", violetSoft: "rgba(169,139,255,0.14)",
};
const MONO_COL = "'IBM Plex Mono', ui-monospace, monospace";
const UI_COL = "'Manrope', system-ui, sans-serif";
const DISP_COL = "'Sora', 'Manrope', system-ui, sans-serif";

const clampCol = (x, a, b) => Math.max(a, Math.min(b, x));
const fmtTr_COL = (m) => `${Math.round(m).toLocaleString("vi-VN")} tr`;

const DEBTORS_COL = [
  { id: "d1", name: "Cty TNHH TM Minh Phát",     code: "131.0042", amount: 320, days: 45, onTime: 0.92, contact: "Anh Tuấn — Kế toán trưởng" },
  { id: "d2", name: "Cty CP Xây dựng Hoàng Gia", code: "131.0017", amount: 280, days: 30, onTime: 0.88, contact: "Chị Hà — Phòng tài chính" },
  { id: "d3", name: "Cty TNHH SX Tân Tiến",      code: "131.0008", amount: 150, days: 60, onTime: 0.70, contact: "Anh Dũng — Giám đốc" },
  { id: "d4", name: "Cty CP Dược phẩm An Khang", code: "131.0051", amount: 95,  days: 15, onTime: 0.95, contact: "Chị Lan — Kế toán" },
  { id: "d5", name: "DNTN Thành Đạt",            code: "131.0029", amount: 60,  days: 22, onTime: 0.80, contact: "Anh Nam — Chủ DN" },
  { id: "d6", name: "Global Tech Solutions Ltd.", code: "131.0063", amount: 480, days: 38, onTime: 0.85, contact: "Mr. James Chen — Finance Manager", lang: "en" },
  { id: "d7", name: "Pacific Trading Co., Ltd.",  code: "131.0071", amount: 210, days: 55, onTime: 0.72, contact: "Ms. Sarah Park — Accounts Payable", lang: "en" },
];
function recoverP_COL(r) {
  const amtPen = r.amount >= 250 ? 0.06 : r.amount >= 120 ? 0.03 : 0;
  return clampCol(0.97 - r.days * 0.004 - (1 - r.onTime) * 0.30 - amtPen, 0.05, 0.97);
}
/* tone tier by overdue days */
function tierCol(days) {
  if (days >= 45) return { key: "urgent", labelKey: "col.tier.urgent", c: C_COL.red, soft: C_COL.redSoft };
  if (days >= 25) return { key: "firm", labelKey: "col.tier.firm", c: C_COL.orange, soft: C_COL.orangeSoft };
  return { key: "gentle", labelKey: "col.tier.gentle", c: C_COL.gold, soft: C_COL.goldSoft };
}

/* AI-drafted message templates per channel & tone */
function draftCol(r, channel) {
  const tier = tierCol(r.days);
  const cty = r.name;

  // English templates for foreign businesses
  if (r.lang === "en") {
    const amtEn = `${r.amount}M VND`;
    if (channel === "email") {
      if (tier.key === "gentle") return {
        subject: `[Payment Reminder] Invoice ${r.code} — ${cty}`,
        body: `Dear ${r.contact},\n\nWe hope this message finds you well. This is a friendly reminder that invoice ${amtEn} (ref: ${r.code}) is now ${r.days} days due.\n\nWe kindly ask you to arrange payment at your earliest convenience. If payment has already been made, please disregard this notice.\n\nThank you for your continued partnership.\n\nBest regards.` };
      if (tier.key === "firm") return {
        subject: `[Overdue ${r.days} Days] Payment Request — ${r.code}`,
        body: `Dear ${r.contact},\n\nWe wish to inform you that invoice ${amtEn} (ref: ${r.code}) is now ${r.days} days overdue. We have not yet received payment.\n\nWe kindly request that you process this payment by end of month to avoid any impact on your credit limit and future orders.\n\nWe look forward to your prompt response.\n\nBest regards.` };
      return {
        subject: `[URGENT] Overdue Invoice ${r.code} — ${r.days} Days — Immediate Action Required`,
        body: `Dear ${r.contact},\n\nInvoice ${amtEn} (ref: ${r.code}) is now seriously overdue by ${r.days} days. This is a formal demand for payment.\n\nWe require full payment within 3 business days. Failure to do so will result in the temporary suspension of supply and escalation to our collections department.\n\nWe trust you will treat this matter with the urgency it deserves.\n\nYours sincerely.` };
    }
    if (channel === "zalo") {
      if (tier.key === "gentle") return { body: `Hi ${r.contact} 👋\nJust a friendly reminder that invoice ${amtEn} (${r.code}) is now due. Please arrange payment at your convenience. Thank you! 🙏` };
      if (tier.key === "firm") return { body: `Hi ${r.contact},\nInvoice ${amtEn} (${r.code}) is ${r.days} days overdue. Please arrange payment before month-end to avoid any impact on future orders. Thank you!` };
      return { body: `Hi ${r.contact},\nInvoice ${amtEn} (${r.code}) is ${r.days} days overdue. Please settle within 3 business days — otherwise we will need to suspend delivery. Your cooperation is appreciated. 🙏` };
    }
    // sms (english)
    if (tier.key === "gentle") return { body: `${cty}: Reminder — invoice ${r.amount}M VND (${r.code}) is due. Please arrange payment. Thank you!` };
    if (tier.key === "firm") return { body: `${cty}: Invoice ${r.amount}M VND (${r.code}) is ${r.days} days overdue. Please pay by month-end. Thank you!` };
    return { body: `[URGENT] ${cty}: Invoice ${r.amount}M VND (${r.code}) overdue ${r.days} days. Pay within 3 days or supply suspended. Contact us immediately!` };
  }

  // Vietnamese templates
  const amt = `${r.amount.toLocaleString("vi-VN")} triệu đồng`;
  if (channel === "email") {
    if (tier.key === "gentle") return { subject: `[Nhắc lịch thanh toán] Công nợ ${r.code} — ${cty}`,
      body: `Kính gửi ${r.contact},\n\nCông ty chúng tôi xin trân trọng nhắc lịch thanh toán khoản công nợ ${amt} (mã ${r.code}), hiện đã đến hạn ${r.days} ngày.\n\nKính mong Quý công ty thu xếp thanh toán trong thời gian sớm nhất. Nếu đã chuyển khoản, xin bỏ qua thông báo này.\n\nTrân trọng cảm ơn sự hợp tác của Quý công ty.` };
    if (tier.key === "firm") return { subject: `[Quá hạn ${r.days} ngày] Đề nghị thanh toán công nợ ${r.code}`,
      body: `Kính gửi ${r.contact},\n\nKhoản công nợ ${amt} (mã ${r.code}) của Quý công ty đã quá hạn ${r.days} ngày. Chúng tôi chưa ghi nhận được thanh toán.\n\nĐề nghị Quý công ty thanh toán trước ngày cuối tháng để tránh ảnh hưởng đến hạn mức tín dụng và các đơn hàng tiếp theo.\n\nRất mong nhận được phản hồi sớm. Trân trọng.` };
    return { subject: `[KHẨN] Công nợ quá hạn ${r.days} ngày — ${r.code} cần xử lý ngay`,
      body: `Kính gửi ${r.contact},\n\nKhoản công nợ ${amt} (mã ${r.code}) đã quá hạn nghiêm trọng (${r.days} ngày). Đây là thông báo nhắc nợ chính thức.\n\nĐề nghị Quý công ty thanh toán trong vòng 03 ngày làm việc. Sau thời hạn này, chúng tôi buộc phải tạm dừng cung cấp hàng hóa/dịch vụ và chuyển hồ sơ sang bộ phận xử lý công nợ.\n\nMong Quý công ty phối hợp. Trân trọng.` };
  }
  if (channel === "zalo") {
    if (tier.key === "gentle") return { body: `Chào ${r.contact} 👋\nDạ ${cty} mình xin nhắc nhẹ khoản công nợ ${amt} (${r.code}) vừa đến hạn ạ. Anh/chị thu xếp giúp em nhé. Em cảm ơn nhiều ạ! 🙏` };
    if (tier.key === "firm") return { body: `Chào ${r.contact},\nKhoản ${amt} (${r.code}) đã quá hạn ${r.days} ngày rồi ạ. Anh/chị hỗ trợ thanh toán giúp em trước cuối tháng nhé, để không ảnh hưởng đơn hàng tới. Em cảm ơn ạ!` };
    return { body: `Chào ${r.contact},\nEm xin thông báo khoản ${amt} (${r.code}) đã quá hạn ${r.days} ngày. Mong anh/chị xử lý trong 3 ngày tới giúp em ạ, nếu không bên em phải tạm dừng giao hàng. Rất mong anh/chị phối hợp 🙏` };
  }
  // sms
  if (tier.key === "gentle") return { body: `${cty}: Nhac lich thanh toan cong no ${r.amount}tr (${r.code}) vua den han. Vui long thu xep TT. Cam on!` };
  if (tier.key === "firm") return { body: `${cty}: Cong no ${r.amount}tr (${r.code}) qua han ${r.days} ngay. De nghi TT truoc cuoi thang de khong anh huong don hang. Cam on!` };
  return { body: `[KHAN] ${cty}: Cong no ${r.amount}tr (${r.code}) qua han ${r.days} ngay. De nghi TT trong 03 ngay, neu khong se tam dung giao hang. LH ngay!` };
}

