  useEffect(() => {
    const l = document.createElement("link"); l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Sora:wght@600;700;800&family=IBM+Plex+Mono:wght@400;500;600&display=swap";
    document.head.appendChild(l); return () => { document.head.removeChild(l); };
  }, []);

  const debtors = DEBTORS_COL.map((r) => ({ ...r, p: recoverP_COL(r), tier: tierCol(r.days) }))
    .sort((a, b) => b.days - a.days);
  const cur = debtors.find((r) => r.id === sel);
  const msg = draftCol(cur, channel);
