const PARTNERS_CR = [
  { id: "p1", name: "Cty CP Thực phẩm An Phú", industryKey: "cr.ind.food", revBn: 180,
    f: { liquidity: 88, leverage: 72, payment: 94, industry: 80, size: 85 }, requested: 500 },
  { id: "p2", name: "Cty TNHH Xây dựng Tiến Phát", industryKey: "cr.ind.construction", revBn: 240,
    f: { liquidity: 55, leverage: 42, payment: 60, industry: 48, size: 78 }, requested: 800 },
  { id: "p3", name: "Cty CP Bán lẻ Hồng Hà", industryKey: "cr.ind.retail", revBn: 95,
    f: { liquidity: 76, leverage: 68, payment: 82, industry: 70, size: 64 }, requested: 350 },
  { id: "p4", name: "DNTN Vận tải Đông Dương", industryKey: "cr.ind.logistics", revBn: 42,
    f: { liquidity: 38, leverage: 30, payment: 45, industry: 52, size: 40 }, requested: 300 },
];

/* explainable factors and their weights */
const FACTORS_CR = [
  { key: "liquidity", nameKey: "cr.f.liquidity", icon: Wallet, w: 0.24, srcKey: "cr.src.financial" },
  { key: "leverage", nameKey: "cr.f.leverage", icon: TrendingDown, w: 0.20, srcKey: "cr.src.financial" },
  { key: "payment", nameKey: "cr.f.payment", icon: History, w: 0.30, srcKey: "cr.src.transactions" },
  { key: "industry", nameKey: "cr.f.industry", icon: Network, w: 0.14, srcKey: "cr.src.industry" },
  { key: "size", nameKey: "cr.f.size", icon: Building2, w: 0.12, srcKey: "cr.src.profile" },
];

const scoreOf_CR = (f) => Math.round(FACTORS_CR.reduce((s, x) => s + f[x.key] * x.w, 0));
function grade_CR(score) {
  if (score >= 80) return { g: "AA", c: C_CR.green, labelKey: "cr.grade.AA", Icon: ShieldCheck, ratio: 1.0 };
  if (score >= 68) return { g: "A", c: C_CR.cyan, labelKey: "cr.grade.A", Icon: ShieldCheck, ratio: 0.8 };
  if (score >= 55) return { g: "BBB", c: C_CR.gold, labelKey: "cr.grade.BBB", Icon: AlertTriangle, ratio: 0.55 };
  if (score >= 42) return { g: "BB", c: C_CR.orange, labelKey: "cr.grade.BB", Icon: AlertTriangle, ratio: 0.3 };
  return { g: "B", c: C_CR.red, labelKey: "cr.grade.B", Icon: ShieldAlert, ratio: 0.12 };
}
const fmtVnd_CR = (m) => `${Math.round(m * 1e6).toLocaleString("vi-VN")} ₫`;

function CreditScore() {
  const { t } = useT();
  const [sel, setSel] = useState(PARTNERS_CR[1]);
  const [phase, setPhase] = useState("idle"); // idle | scoring | done
  const [progress, setProgress] = useState(0); // 0..5 factors revealed
  const timers = useRef([]);

  useEffect(() => {
    const l = document.createElement("link"); l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Sora:wght@600;700;800&family=IBM+Plex+Mono:wght@400;500;600&display=swap";
    document.head.appendChild(l); return () => { document.head.removeChild(l); };
  }, []);

  const clearTimers = () => { timers.current.forEach(clearTimeout); timers.current = []; };
  useEffect(() => () => clearTimers(), []);

  const run = () => {
    clearTimers();
    setPhase("scoring"); setProgress(0);
    FACTORS_CR.forEach((_, i) => timers.current.push(setTimeout(() => setProgress(i + 1), 700 * (i + 1))));
    timers.current.push(setTimeout(() => setPhase("done"), 700 * FACTORS_CR.length + 500)); // ~5s total
  };
  const pick = (p) => { clearTimers(); setSel(p); setPhase("idle"); setProgress(0); };

  const score = scoreOf_CR(sel.f);
  const g = grade_CR(score);
  const safeLimit = Math.round(sel.requested * g.ratio / 10) * 10;
  const reveal = phase === "done" ? 5 : progress;

  return (
    <div style={{ fontFamily: UI_CR, color: C_CR.txt }}>
      <style>{`
        *{box-sizing:border-box}
        @keyframes rise{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
        @keyframes spin{to{transform:rotate(360deg)}}
        @keyframes fill{from{stroke-dashoffset:var(--circ)}}
        @keyframes pop{from{opacity:0;transform:scale(.85)}to{opacity:1;transform:none}}
        .card{animation:rise .5s cubic-bezier(.2,.7,.3,1) both}
        .tnum{font-family:${MONO_CR};font-variant-numeric:tabular-nums}
        .btn{cursor:pointer;transition:all .15s;border:none;font-family:${UI_CR}}
        .btn:hover{filter:brightness(1.1)}
        .live{animation:pulse 1.4s ease-in-out infinite}
        .spin{animation:spin 1s linear infinite}
        .pop{animation:pop .4s cubic-bezier(.2,.7,.3,1) both}
        ::-webkit-scrollbar{height:8px;width:8px}::-webkit-scrollbar-thumb{background:rgba(255,255,255,.12);border-radius:8px}
      `}</style>

      <div style={{ maxWidth: 1180, margin: "0 auto" }}>
        {/* HEADER */}
        <header style={{ display: "flex", alignItems: "center", gap: 13, flexWrap: "wrap", justifyContent: "space-between", marginBottom: 18 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
            <div style={{ width: 42, height: 42, borderRadius: 12, display: "grid", placeItems: "center", background: `linear-gradient(135deg, ${C_CR.cyan}, #2E9BD6)` }}><Gauge size={22} color="#06202f" strokeWidth={2.3} /></div>
            <div>
              <div style={{ fontFamily: DISP_CR, fontWeight: 800, fontSize: 19, letterSpacing: "-0.02em" }}>{t("cr.title")}</div>
              <div style={{ fontSize: 12.5, color: C_CR.sub, marginTop: 1 }}>{t("cr.subtitle")}</div>
            </div>
          </div>
          <span style={{ display: "inline-flex", alignItems: "center", gap: 7, fontSize: 12, fontWeight: 700, color: C_CR.violet, background: C_CR.violetSoft, padding: "7px 13px", borderRadius: 20 }}><Bot size={13} />{t("cr.badge")}</span>
        </header>

        <div style={{ display: "grid", gap: 16, gridTemplateColumns: "minmax(0,250px) minmax(0,1fr)" }}>
          {/* PARTNER LIST */}
          <section className="card" style={panelCr}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}><Building2 size={16} color={C_CR.gold} /><h3 style={{ ...h3, fontSize: 15 }}>{t("cr.partners")}</h3></div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {PARTNERS_CR.map((p) => {
                const on = p.id === sel.id; const pg = grade_CR(scoreOf_CR(p.f));
                return (
                  <button key={p.id} className="btn" onClick={() => pick(p)} style={{ textAlign: "left", padding: "11px 12px", borderRadius: 12, background: on ? C_CR.cyanSoft : C_CR.panel2, border: `1px solid ${on ? C_CR.cyan + "66" : C_CR.line}` }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}>
                      <div style={{ minWidth: 0 }}>
                        <div style={{ fontWeight: 700, fontSize: 12.8, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.name}</div>
                        <div style={{ fontSize: 10.8, color: C_CR.sub, marginTop: 2 }}>{t(p.industryKey)} · {t("cr.revFmt", { n: p.revBn })}</div>
                      </div>
                      <span className="tnum" style={{ flex: "0 0 auto", fontSize: 11, fontWeight: 800, color: pg.c, background: pg.c + "1f", padding: "2px 7px", borderRadius: 6 }}>{pg.g}</span>
                    </div>
                  </button>
                );
              })}
            </div>
            <div style={{ marginTop: 13, padding: "11px 12px", borderRadius: 11, background: C_CR.violetSoft, border: `1px solid ${C_CR.violet}33`, fontSize: 11.3, color: C_CR.txt, lineHeight: 1.5 }}>
              {t("cr.datasources")}
            </div>
          </section>

          {/* SCORING ENGINE */}
          <section className="card" style={panelCr}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 10, flexWrap: "wrap", marginBottom: 6 }}>
              <div style={{ minWidth: 0 }}>
                <div style={{ fontFamily: DISP_CR, fontWeight: 700, fontSize: 17 }}>{sel.name}</div>
                <div style={{ fontSize: 12, color: C_CR.sub, marginTop: 2 }}>{t(sel.industryKey)} · {t("cr.rev", { rev: t("cr.revFmt", { n: sel.revBn }) })} · {t("cr.req", { r: sel.requested })}</div>
              </div>
              <button className="btn" onClick={run} disabled={phase === "scoring"} style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "10px 18px", borderRadius: 11, fontWeight: 800, fontSize: 13.5, color: "#06202f", background: phase === "scoring" ? "#33415566" : `linear-gradient(135deg, ${C_CR.cyan}, #2E9BD6)`, opacity: phase === "scoring" ? .7 : 1 }}>
                {phase === "scoring" ? <><RefreshCw size={15} className="spin" />{t("cr.scoring")}</> : phase === "done" ? <><RefreshCw size={15} />{t("cr.rescore")}</> : <><Zap size={15} />{t("cr.score.btn")}</>}
              </button>
            </div>

            {phase === "idle" ? (
              <div style={{ padding: "40px 16px", textAlign: "center", color: C_CR.sub }}>
                <Cpu size={30} color={C_CR.sub} style={{ opacity: .5 }} />
                <div style={{ fontSize: 13, marginTop: 10, lineHeight: 1.6, maxWidth: 380, margin: "10px auto 0" }}>{t("cr.idle.hint")}</div>
              </div>
            ) : (
              <div style={{ display: "grid", gap: 18, gridTemplateColumns: "minmax(0,168px) minmax(0,1fr)", marginTop: 14, alignItems: "start" }}>
                {/* score dial */}
                <div style={{ textAlign: "center" }}>
                  <ScoreDial_CR score={phase === "done" ? score : Math.round(score * reveal / 5)} g={g} running={phase === "scoring"} tFn={t} />
                  {phase === "done" && (
                    <div className="pop" style={{ marginTop: 12 }}>
                      <div style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 13, fontWeight: 800, color: g.c, background: g.c + "1f", padding: "5px 13px", borderRadius: 20 }}><g.Icon size={14} />{t("cr.grade.badge", { g: g.g, label: t(g.labelKey) })}</div>
                    </div>
                  )}
                </div>

                {/* factor breakdown */}
                <div>
                  <div style={{ fontSize: 12, fontWeight: 700, color: C_CR.sub, marginBottom: 10, display: "flex", alignItems: "center", gap: 7 }}>
                    {phase === "scoring" ? <><Cpu size={13} className="live" color={C_CR.cyan} />{t("cr.analyzing")}</> : <><CheckCircle2 size={13} color={C_CR.green} />{t("cr.transparent")}</>}
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
                    {FACTORS_CR.map((f, i) => {
                      const shown = i < reveal; const Ic = f.icon; const v = sel.f[f.key];
                      const vc = v >= 75 ? C_CR.green : v >= 55 ? C_CR.gold : v >= 42 ? C_CR.orange : C_CR.red;
                      return (
                        <div key={f.key} style={{ opacity: shown ? 1 : 0.32, transition: "opacity .3s" }} className={shown ? "pop" : ""}>
                          <div style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 5 }}>
                            <div style={{ width: 26, height: 26, borderRadius: 7, flex: "0 0 auto", display: "grid", placeItems: "center", background: shown ? vc + "22" : "rgba(255,255,255,.05)" }}>
                              {shown ? <Ic size={14} color={vc} /> : <RefreshCw size={13} className="spin" color={C_CR.sub} />}
                            </div>
                            <span style={{ fontSize: 12.3, fontWeight: 600, flex: 1, minWidth: 0, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{t(f.nameKey)}</span>
                            <span style={{ fontSize: 10, color: C_CR.sub, flex: "0 0 auto", whiteSpace: "nowrap" }}>{t(f.srcKey)}</span>
                            <span className="tnum" style={{ fontSize: 12.5, fontWeight: 800, color: shown ? vc : C_CR.sub, width: 30, flex: "0 0 auto", textAlign: "right" }}>{shown ? v : "··"}</span>
                          </div>
                          <div style={{ display: "flex", alignItems: "center", gap: 8, paddingLeft: 35 }}>
                            <div style={{ flex: 1, height: 6, borderRadius: 4, background: "rgba(255,255,255,.07)", overflow: "hidden" }}>
                              <div style={{ width: shown ? `${v}%` : "0%", height: "100%", background: vc, borderRadius: 4, transition: "width .5s" }} />
                            </div>
                            <span className="tnum" style={{ fontSize: 9.5, color: C_CR.sub, flex: "0 0 auto", whiteSpace: "nowrap", textAlign: "right" }}>{t("cr.weight", { w: Math.round(f.w * 100) })}</span>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            )}

            {/* CREDIT LIMIT RECOMMENDATION */}
            {phase === "done" && (
              <div className="pop" style={{ marginTop: 18, padding: "16px 18px", borderRadius: 14, background: g.c + "12", border: `1px solid ${g.c}55` }}>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 16, alignItems: "center", justifyContent: "space-between" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 12, minWidth: 0, flex: "1 1 260px" }}>
                    <div style={{ width: 42, height: 42, borderRadius: 11, flex: "0 0 auto", display: "grid", placeItems: "center", background: g.c + "22" }}><ShieldCheck size={22} color={g.c} /></div>
                    <div style={{ minWidth: 0 }}>
                      <div style={{ fontSize: 12, color: C_CR.sub }}>{t("cr.limit.title")}</div>
                      <div className="tnum" style={{ fontFamily: DISP_CR, fontSize: 24, fontWeight: 800, color: g.c, lineHeight: 1.15, whiteSpace: "nowrap" }}>{fmtVnd_CR(safeLimit)}</div>
                    </div>
                  </div>
                  <div style={{ display: "flex", gap: 20, flexWrap: "wrap", flex: "0 1 auto" }}>
                    <Mini_CR label={t("cr.limit.requested")} value={`${sel.requested} tr`} c={C_CR.sub} />
                    <Mini_CR label={t("cr.limit.approved")} value={`${safeLimit} tr`} c={g.c} />
                    <Mini_CR label={t("cr.limit.ratio")} value={`${Math.round(g.ratio * 100)}%`} c={g.c} />
                  </div>
                </div>
                <div style={{ fontSize: 11.8, color: C_CR.sub, marginTop: 12, paddingTop: 12, borderTop: `1px solid ${C_CR.line}`, lineHeight: 1.55 }}>
                  {safeLimit >= sel.requested
                    ? t("cr.limit.good", { g: g.g, req: sel.requested })
                    : t("cr.limit.reduced", { g: g.g, label: t(g.labelKey), safe: safeLimit, req: sel.requested, weak: t(weakest_CR(sel.f)) })}
                </div>
                <div style={{ marginTop: 12, display: "flex", gap: 9, flexWrap: "wrap" }}>
                  <button className="btn" style={{ display: "inline-flex", alignItems: "center", gap: 7, padding: "10px 16px", borderRadius: 10, fontWeight: 800, fontSize: 13, color: "#0b1a10", background: `linear-gradient(135deg, ${C_CR.green}, #1FA877)` }}><Check size={15} />{t("cr.apply")}</button>
                  <button className="btn" style={{ display: "inline-flex", alignItems: "center", gap: 7, padding: "10px 16px", borderRadius: 10, fontWeight: 700, fontSize: 13, color: C_CR.txt, background: "rgba(255,255,255,.05)", border: `1px solid ${C_CR.line}` }}><Clock size={14} />{t("cr.schedule")}</button>
                </div>
              </div>
            )}
          </section>
        </div>

        <footer style={{ marginTop: 18, fontSize: 11.5, color: C_CR.sub, textAlign: "center", lineHeight: 1.6 }}>
          {t("cr.footer")}
        </footer>
      </div>
    </div>
  );
}

function weakest_CR(f) {
  const map = { liquidity: "cr.weak.liquidity", leverage: "cr.weak.leverage", payment: "cr.weak.payment", industry: "cr.weak.industry", size: "cr.weak.size" };
  const k = FACTORS_CR.map((x) => x.key).sort((a, b) => f[a] - f[b])[0];
  return map[k];
}

const panelCr = { background: C_CR.panel, border: `1px solid ${C_CR.line}`, borderRadius: 18, padding: "16px 18px 14px", boxShadow: "0 18px 40px -28px rgba(0,0,0,.7)" };
const h3Cr = { margin: 0, fontFamily: DISP_CR, fontWeight: 700, fontSize: 16, letterSpacing: "-0.01em", color: C_CR.txt };

function Mini_CR({ label, value, c }) { return <div style={{ textAlign: "right" }}><div className="tnum" style={{ fontSize: 15, fontWeight: 800, color: c, lineHeight: 1.1 }}>{value}</div><div style={{ fontSize: 10, color: C_CR.sub, marginTop: 1 }}>{label}</div></div>; }

function ScoreDial_CR({ score, g, running, tFn }) {
  const R = 52, circ = 2 * Math.PI * R;
  const pctv = Math.max(0, Math.min(100, score)) / 100;
  return (
    <div style={{ position: "relative", width: 140, height: 140, margin: "0 auto" }}>
      <svg width="140" height="140" viewBox="0 0 140 140">
        <circle cx="70" cy="70" r={R} fill="none" stroke="rgba(255,255,255,.08)" strokeWidth="11" />
        <circle cx="70" cy="70" r={R} fill="none" stroke={g.c} strokeWidth="11" strokeLinecap="round"
          strokeDasharray={circ} strokeDashoffset={circ * (1 - pctv)}
          transform="rotate(-90 70 70)" style={{ transition: "stroke-dashoffset .6s ease, stroke .3s" }} />
      </svg>
      <div style={{ position: "absolute", inset: 0, display: "grid", placeItems: "center", textAlign: "center" }}>
        <div>
          <div className={`tnum ${running ? "live" : ""}`} style={{ fontSize: 34, fontWeight: 800, color: g.c, lineHeight: 1 }}>{score}</div>
          <div style={{ fontSize: 10.5, color: C_CR.sub, marginTop: 2 }}>{tFn ? tFn("cr.score.unit") : "/ 100"}</div>
        </div>
      </div>
    </div>
  );
}


