/* ================= INVOICE PROCESSING MODULE (reads uploaded Excel/CSV) ================= */
/* palette */
const C_INV = {
  bg: "#0A0E18", panel: "#121A2B", panel2: "#0E1422",
  line: "rgba(255,255,255,0.08)", line2: "rgba(255,255,255,0.045)",
  txt: "#E9EDF6", sub: "#8A93AA",
  gold: "#F5B83D", goldSoft: "rgba(245,184,61,0.14)",
  green: "#37D29A", greenSoft: "rgba(55,210,154,0.12)",
  red: "#FF5269", redSoft: "rgba(255,82,105,0.13)",
  orange: "#FF9A3D", orangeSoft: "rgba(255,154,61,0.13)",
  cyan: "#54C7FF", cyanSoft: "rgba(84,199,255,0.12)",
  violet: "#A98BFF", violetSoft: "rgba(169,139,255,0.14)",
};
const MONO_INV = "'IBM Plex Mono', ui-monospace, monospace";
const UI_INV = "'Manrope', system-ui, sans-serif";
const DISP_INV = "'Sora', 'Manrope', system-ui, sans-serif";

const fmtVnd_INV = (n) => (Number(n) || 0).toLocaleString("vi-VN") + " ₫";
const fmtTr_INV = (n) => ((Number(n) || 0) / 1e6).toLocaleString("vi-VN", { maximumFractionDigits: 2 }) + " tr";

/* column header aliases → canonical field (matches MISA/FAST export wording) */
const COLMAP_INV = {
  stt: ["stt", "số tt", "tt"],
  date: ["ngày hđ", "ngày hóa đơn", "ngày", "ngày lập"],
  serial: ["ký hiệu", "ký hiệu hđ", "mẫu số ký hiệu"],
  no: ["số hđ", "số hóa đơn", "số"],
  buyerTax: ["mst người mua", "mã số thuế người mua", "mst", "mã số thuế"],
  buyer: ["tên người mua", "tên đơn vị", "khách hàng", "người mua"],
  item: ["tên hàng hóa, dịch vụ", "tên hàng hóa", "hàng hóa, dịch vụ", "diễn giải", "tên hàng"],
  unit: ["đvt", "đơn vị tính"],
  qty: ["số lượng", "sl"],
  price: ["đơn giá"],
  amount: ["tiền hàng", "thành tiền", "tiền hàng chưa thuế"],
  ckRate: ["tỷ lệ ck (%)", "tỷ lệ ck", "tỷ lệ chiết khấu"],
  ck: ["tiền ck", "tiền chiết khấu", "chiết khấu"],
  net: ["tiền hàng sau ck", "tiền hàng đã trừ ck", "cộng tiền hàng"],
  vatRate: ["thuế suất (%)", "thuế suất", "thuế suất gtgt"],
  vat: ["tiền thuế gtgt", "tiền thuế", "thuế gtgt"],
  total: ["tổng thanh toán", "tổng cộng tiền thanh toán", "tổng tiền thanh toán", "tổng tiền"],
  pay: ["hình thức tt", "hình thức thanh toán", "hình thức tt"],
};
const norm_INV = (s) => String(s == null ? "" : s).trim().toLowerCase().replace(/\s+/g, " ");
function findHeaderRow_INV(rows) {
  for (let i = 0; i < Math.min(rows.length, 25); i++) {
    const cells = (rows[i] || []).map(norm_INV);
    const hit = cells.filter((c) => c === "stt" || COLMAP_INV.no.includes(c) || COLMAP_INV.total.includes(c)).length;
    if (hit >= 2) return i;
  }
  return 0;
}
function buildColIndex_INV(headerCells) {
  const idx = {}; const hc = headerCells.map(norm_INV);
  for (const field of Object.keys(COLMAP_INV)) {
    for (const alias of COLMAP_INV[field]) {
      const j = hc.indexOf(alias);
      if (j >= 0) { idx[field] = j; break; }
    }
  }
  return idx;
}
const toNum_INV = (v) => {
  if (v == null || v === "") return 0;
  if (typeof v === "number") return v;
  const s = String(v).replace(/[^\d,.-]/g, "");
  // vi-VN style: dot thousand, comma decimal -> normalize
  if (s.indexOf(",") >= 0 && s.indexOf(".") >= 0) return parseFloat(s.replace(/\./g, "").replace(",", ".")) || 0;
  if (s.indexOf(",") >= 0 && s.indexOf(".") < 0) return parseFloat(s.replace(",", ".")) || 0;
  return parseFloat(s.replace(/,/g, "")) || 0;
};

/* parse a SheetJS AOA into invoice line objects */
function parseInvoices_INV(aoa) {
  if (!aoa || !aoa.length) return { lines: [], colIndex: {}, headerRow: -1 };
  const hr = findHeaderRow_INV(aoa);
  const colIndex = buildColIndex_INV(aoa[hr] || []);
  const get = (row, f) => (colIndex[f] != null ? row[colIndex[f]] : undefined);
  const lines = [];
  for (let i = hr + 1; i < aoa.length; i++) {
    const row = aoa[i] || [];
    const stt = get(row, "stt");
    const total = toNum_INV(get(row, "total"));
    const item = get(row, "item");
    // skip totals/blank rows: need a numeric STT or an item name + total
    const hasStt = stt != null && String(stt).trim() !== "" && !isNaN(Number(stt));
    if (!hasStt && !(item && total)) continue;
    const amount = toNum_INV(get(row, "amount"));
    const ck = toNum_INV(get(row, "ck"));
    const net = colIndex.net != null ? toNum_INV(get(row, "net")) : amount - ck;
    const vat = toNum_INV(get(row, "vat"));
    const vatRate = toNum_INV(get(row, "vatRate"));
    lines.push({
      stt: hasStt ? Number(stt) : lines.length + 1,
      date: String(get(row, "date") ?? "").trim(),
      serial: String(get(row, "serial") ?? "").trim(),
      no: String(get(row, "no") ?? "").trim(),
      buyerTax: String(get(row, "buyerTax") ?? "").trim(),
      buyer: String(get(row, "buyer") ?? "").trim(),
      item: String(item ?? "").trim(),
      unit: String(get(row, "unit") ?? "").trim(),
      qty: toNum_INV(get(row, "qty")),
      price: toNum_INV(get(row, "price")),
      amount, ckRate: toNum_INV(get(row, "ckRate")), ck, net, vatRate, vat,
      total: total || net + vat,
      pay: String(get(row, "pay") ?? "").trim(),
    });
  }
  return { lines, colIndex, headerRow: hr };
}

/* TT200 journal entries for a sales-invoice line */
function classify_INV(ln) {
  const e = [];
  e.push({ acc: "131", side: "Nợ", name: `Phải thu KH${ln.buyer ? " · " + ln.buyer : ""}`, amount: ln.total, c: C_INV.green });
  if (ln.ck > 0) e.push({ acc: "521", side: "Nợ", name: "Chiết khấu thương mại", amount: ln.ck, c: C_INV.orange });
  e.push({ acc: "511", side: "Có", name: "Doanh thu bán hàng & CCDV", amount: ln.net, c: C_INV.cyan });
  if (ln.vat > 0) e.push({ acc: "3331", side: "Có", name: `Thuế GTGT đầu ra (${ln.vatRate || 0}%)`, amount: ln.vat, c: C_INV.violet });
  return e;
}
/* anomaly checks per line */
function checkLine_INV(ln) {
  const out = [];
  const calcNet = Math.round(ln.amount - ln.ck);
  const calcTotal = Math.round(ln.net + ln.vat);
  out.push({ ok: Math.abs(calcTotal - Math.round(ln.total)) <= 1, label: "Tổng = (tiền hàng − CK) + thuế", v: `${calcTotal.toLocaleString("vi-VN")} ≈ ${Math.round(ln.total).toLocaleString("vi-VN")}` });
  out.push({ ok: /^\d{10}(-\d{3})?$/.test(ln.buyerTax), label: "MST người mua hợp lệ", v: ln.buyerTax || "(trống)" });
  out.push({ ok: ln.vatRate > 0, label: "Có thuế suất GTGT", v: ln.vatRate ? ln.vatRate + "%" : "(trống)" });
  return out;
}

/* 13-week cashflow: collections spread across weeks by invoice date day-of-month */
const START_CASH_INV = 180;
const INFLOW_INV  = [60, 55, 65, 50, 58, 62, 54, 66, 58, 60, 56, 64, 60];
const OUTFLOW_INV = [80, 70, 95, 120, 78, 140, 86, 124, 80, 70, 72, 126, 82];
function weekRanges_INV(y, m) {
  const start = new Date(y, m, 1); const out = [];
  for (let i = 0; i < 13; i++) {
    const a = new Date(start); a.setDate(start.getDate() + i * 7);
    const b = new Date(a); b.setDate(a.getDate() + 6);
    const f = (d) => `${String(d.getDate()).padStart(2, "0")}/${String(d.getMonth() + 1).padStart(2, "0")}`;
    out.push(`${f(a)}–${f(b)}`);
  }
  return out;
}
/* map an invoice to a collection week (assume collected ~4 weeks after issue, within horizon) */
function collectWeek_INV(ln, baseMonth) {
  const m = /(\d{1,2})[\/\-](\d{1,2})/.exec(ln.date);
  let dom = 1; if (m) dom = parseInt(m[1], 10) || 1;
  const wk = Math.min(12, Math.max(0, Math.floor((dom - 1) / 7) + 4)); // issue week + ~4w credit
  return wk;
}
function buildCashflow_INV(lines, baseY, baseM) {
  const ranges = weekRanges_INV(baseY, baseM);
  const collectAt = Array(13).fill(0);
  lines.forEach((ln) => { collectAt[collectWeek_INV(ln)] += ln.total / 1e6; });
  let balBase = START_CASH_INV, balRecv = START_CASH_INV;
  let minBase = Infinity, minRecv = Infinity, fnBase = -1, fnRecv = -1;
  const data = ranges.map((rg, i) => {
    balBase += INFLOW_INV[i] - OUTFLOW_INV[i];
    balRecv += INFLOW_INV[i] - OUTFLOW_INV[i] + collectAt[i];
    if (balBase < minBase) minBase = balBase;
    if (balRecv < minRecv) minRecv = balRecv;
    if (balBase < 0 && fnBase < 0) fnBase = i;
    if (balRecv < 0 && fnRecv < 0) fnRecv = i;
    return { name: `T${i + 1}`, idx: i, range: rg, base: Math.round(balBase), recv: Math.round(balRecv), collect: Math.round(collectAt[i]) };
  });
  return { data, ranges, collectAt, minBase: Math.round(minBase), minRecv: Math.round(minRecv), firstNegBase: fnBase, firstNegRecv: fnRecv };
}

const STAGES_INV = [
  { k: "ocr", icon: ScanLine, c: C_INV.cyan },
  { k: "cls", icon: Tag, c: C_INV.gold },
  { k: "chk", icon: ShieldCheck, c: C_INV.violet },
  { k: "cash", icon: Wallet, c: C_INV.green },
];

function InvoiceProcess_INV() {
  const { t } = useT();
  const [lines, setLines] = useState(null);
  const [meta, setMeta] = useState({ name: "", headerRow: -1, cols: 0, mapped: 0 });
  const [stage, setStage] = useState(-1);
  const [running, setRunning] = useState(false);
  const [err, setErr] = useState("");
  const [sel, setSel] = useState(0);
  const fileRef = useRef(null);
  const timer = useRef(null);

  useEffect(() => () => clearInterval(timer.current), []);

  // khôi phục lần upload gần nhất từ Supabase (nếu có)
  useEffect(() => {
    let alive = true;
    loadLatestInvoiceUpload()
      .then((saved) => {
        if (!alive || !saved || !saved.lines.length) return;
        setLines((cur) => {
          if (cur) return cur; // user đã upload file mới trong lúc chờ
          setMeta({ name: saved.meta.name, headerRow: saved.meta.headerRow, cols: saved.meta.cols, mapped: saved.meta.mapped });
          setSel(0);
          setStage(STAGES_INV.length); // pipeline coi như đã chạy xong
          return saved.lines;
        });
      })
      .catch((ex) => console.warn("Supabase load:", ex.message));
    return () => { alive = false; };
  }, []);

  const onFile = (e) => {
    const f = e.target.files && e.target.files[0]; if (!f) return;
    setErr(""); clearInterval(timer.current); setStage(-1); setRunning(false);
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const wb = XLSX.read(ev.target.result, { type: "array" });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, raw: true, defval: "" });
        const { lines: ls, colIndex, headerRow } = parseInvoices_INV(aoa);
        if (!ls.length) { setErr(t("inv.err.noRows")); setLines(null); return; }
        setLines(ls); setSel(0);
        const m = { name: f.name, headerRow: headerRow + 1, cols: (aoa[headerRow] || []).length, mapped: Object.keys(colIndex).length };
        setMeta(m);
        runPipeline();
        saveInvoiceUpload(f.name, m, ls).catch((ex) => console.warn("Supabase save:", ex.message));
      } catch (ex) { setErr(t("inv.err.read") + ex.message); setLines(null); }
    };
    reader.readAsArrayBuffer(f);
  };

  const runPipeline = () => {
    setRunning(true); setStage(0); let i = 0;
    timer.current = setInterval(() => {
      i++;
      if (i > STAGES_INV.length) { clearInterval(timer.current); setStage(STAGES_INV.length); setRunning(false); }
      else setStage(i);
    }, 950);
  };
  const reset = () => { clearInterval(timer.current); setRunning(false); setStage(-1); setLines(null); setErr(""); setMeta({ name: "", headerRow: -1, cols: 0, mapped: 0 }); if (fileRef.current) fileRef.current.value = ""; };
  const done = (k) => stage > STAGES_INV.findIndex((s) => s.k === k);

  // aggregates
  const totals = lines ? lines.reduce((a, l) => ({ net: a.net + l.net, vat: a.vat + l.vat, total: a.total + l.total, ck: a.ck + l.ck }), { net: 0, vat: 0, total: 0, ck: 0 }) : null;
  const cf = (lines && done("chk")) ? buildCashflow_INV(lines, 2020, 8) : null;
  const cur = lines ? lines[Math.min(sel, lines.length - 1)] : null;
  const warnCount = lines ? lines.reduce((a, l) => a + checkLine_INV(l).filter((c) => !c.ok).length, 0) : 0;

  return (
    <div style={{ fontFamily: UI_INV, color: C_INV.txt }}>
      <style>{`
        *{box-sizing:border-box}
        @keyframes rise{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.45}}
        @keyframes spin{to{transform:rotate(360deg)}}
        .card{animation:rise .5s cubic-bezier(.2,.7,.3,1) both}
        .tnum{font-family:${MONO_INV};font-variant-numeric:tabular-nums}
        .btn{cursor:pointer;transition:all .15s;border:none;font-family:${UI_INV}}
        .btn:hover{filter:brightness(1.09)}
        .live{animation:pulse 1.5s ease-in-out infinite}
        .spin{animation:spin 1s linear infinite}
        .rowh:hover{background:rgba(255,255,255,.03)}
        ::-webkit-scrollbar{height:8px;width:8px}::-webkit-scrollbar-thumb{background:rgba(255,255,255,.12);border-radius:8px}
      `}</style>

      <div style={{ maxWidth: 1200, margin: "0 auto" }}>
        {/* HEADER + upload */}
        <header style={{ display: "flex", alignItems: "center", gap: 14, flexWrap: "wrap", justifyContent: "space-between", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
            <div style={{ width: 42, height: 42, borderRadius: 12, display: "grid", placeItems: "center", background: `linear-gradient(135deg, ${C_INV.green}, #1FA877)` }}><Receipt size={22} color="#06251a" strokeWidth={2.3} /></div>
            <div>
              <div style={{ fontFamily: DISP_INV, fontWeight: 800, fontSize: 19, letterSpacing: "-0.02em" }}>{t("inv.title")}</div>
              <div style={{ fontSize: 12.5, color: C_INV.sub, marginTop: 1 }}>{t("inv.subtitle")}</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 9 }}>
            <input ref={fileRef} type="file" accept=".xlsx,.xls,.csv" onChange={onFile} style={{ display: "none" }} />
            <button className="btn" onClick={() => fileRef.current && fileRef.current.click()} style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "10px 18px", borderRadius: 10, fontWeight: 800, fontSize: 13.5, color: "#06251a", background: `linear-gradient(135deg, ${C_INV.green}, #1FA877)` }}><FileSpreadsheet size={16} />{t("inv.upload")}</button>
            {lines && <button className="btn" onClick={reset} title={t("inv.reset")} style={{ display: "grid", placeItems: "center", width: 40, height: 40, borderRadius: 10, color: C_INV.sub, background: "rgba(255,255,255,.05)", border: `1px solid ${C_INV.line}` }}><RotateCcw size={16} /></button>}
          </div>
        </header>

        {/* empty state */}
        {!lines && (
          <div className="card" style={{ ...panelInv, padding: "34px 22px", textAlign: "center", border: `1.5px dashed ${C_INV.line}` }}>
            <div style={{ width: 56, height: 56, borderRadius: 16, margin: "0 auto 14px", display: "grid", placeItems: "center", background: C_INV.greenSoft }}><FileSpreadsheet size={28} color={C_INV.green} /></div>
            <div style={{ fontFamily: DISP_INV, fontWeight: 700, fontSize: 16 }}>{t("inv.empty.title")}</div>
            <div style={{ fontSize: 12.8, color: C_INV.sub, marginTop: 6, maxWidth: 560, marginInline: "auto", lineHeight: 1.6 }}>
              {t("inv.empty.desc")}
            </div>
            {err && <div style={{ marginTop: 14, display: "inline-flex", alignItems: "center", gap: 7, fontSize: 12.5, color: C_INV.red, background: C_INV.redSoft, border: `1px solid ${C_INV.red}44`, padding: "8px 14px", borderRadius: 10 }}><AlertTriangle size={14} />{err}</div>}
          </div>
        )}

        {lines && (
          <>
            {/* file meta + pipeline */}
            <div className="card" style={{ ...panelInv, padding: "12px 16px", marginBottom: 16 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", marginBottom: 11 }}>
                <FileSpreadsheet size={16} color={C_INV.green} />
                <span style={{ fontWeight: 700, fontSize: 13 }}>{meta.name}</span>
                <span className="tnum" style={{ fontSize: 11, color: C_INV.sub, background: "rgba(255,255,255,.04)", padding: "3px 9px", borderRadius: 6 }}>{t("inv.meta", { n: lines.length, row: meta.headerRow, cols: meta.mapped })}</span>
              </div>
              <div style={{ display: "flex", gap: 8, alignItems: "stretch", flexWrap: "wrap" }}>
                {STAGES_INV.map((s, i) => { const Ic = s.icon; const isDone = stage > i; const isCur = stage === i; return (
                  <React.Fragment key={s.k}>
                    <div style={{ flex: "1 1 190px", display: "flex", gap: 10, alignItems: "center", padding: "10px 12px", borderRadius: 11, background: isCur ? s.c + "18" : C_INV.panel2, border: `1px solid ${isCur ? s.c + "66" : isDone ? C_INV.green + "33" : C_INV.line}`, transition: "all .3s" }}>
                      <div className={isCur ? "live" : ""} style={{ width: 30, height: 30, borderRadius: 8, flex: "0 0 auto", display: "grid", placeItems: "center", background: isDone ? C_INV.green + "22" : s.c + "22" }}>
                        {isDone ? <CheckCircle2 size={16} color={C_INV.green} /> : isCur ? <Ic size={16} color={s.c} className="spin" /> : <Ic size={16} color={s.c} />}
                      </div>
                      <div style={{ minWidth: 0 }}><div style={{ fontSize: 12, fontWeight: 700, whiteSpace: "nowrap" }}>{t("inv.stage." + s.k)}</div><div style={{ fontSize: 10, color: C_INV.sub, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{t("inv.stage." + s.k + ".d")}</div></div>
                    </div>
                    {i < STAGES_INV.length - 1 && <div style={{ display: "grid", placeItems: "center", color: stage > i ? C_INV.green : C_INV.sub }}><ArrowRight size={15} /></div>}
                  </React.Fragment>
                ); })}
              </div>
            </div>

            {/* KPI summary */}
            <div style={{ display: "grid", gap: 12, gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", marginBottom: 16, opacity: done("ocr") ? 1 : .4, transition: "opacity .4s" }}>
              <KpiInv label={t("inv.kpi.count")} v={String(lines.length)} c={C_INV.cyan} icon={<Receipt size={15} />} />
              <KpiInv label={t("inv.kpi.net")} v={fmtTr_INV(totals.net)} c={C_INV.gold} icon={<Coins size={15} />} />
              <KpiInv label={t("inv.kpi.vat")} v={fmtTr_INV(totals.vat)} c={C_INV.violet} icon={<Percent size={15} />} />
              <KpiInv label={t("inv.kpi.total")} v={fmtTr_INV(totals.total)} c={C_INV.green} icon={<Wallet size={15} />} />
            </div>

            <div style={{ display: "grid", gap: 16, gridTemplateColumns: "minmax(0,1.25fr) minmax(0,1fr)" }}>
              {/* LEFT: invoice table */}
              <section className="card" style={panelInv}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}><ScanLine size={17} color={C_INV.cyan} /><h3 style={h3Inv}>{t("inv.tbl.read", { n: lines.length })}</h3></div>
                <div style={{ overflowX: "auto" }}><div style={{ minWidth: 560 }}>
                  <div style={{ display: "grid", gridTemplateColumns: "30px 70px minmax(0,1.6fr) 84px 90px 70px", gap: 8, padding: "0 10px 7px", fontSize: 10.5, color: C_INV.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".03em" }}>
                    <span>#</span><span>{t("inv.tbl.no")}</span><span>{t("inv.tbl.customer")}</span><span style={{ textAlign: "right" }}>{t("inv.tbl.total")}</span><span style={{ textAlign: "right" }}>{t("inv.tbl.tax")}</span><span style={{ textAlign: "center" }}>{t("inv.tbl.warn")}</span>
                  </div>
                  {lines.map((ln, i) => { const warns = checkLine_INV(ln).filter((c) => !c.ok).length; const on = i === sel; return (
                    <button key={i} onClick={() => setSel(i)} className="rowh" style={{ width: "100%", textAlign: "left", cursor: "pointer", display: "grid", gridTemplateColumns: "30px 70px minmax(0,1.6fr) 84px 90px 70px", gap: 8, alignItems: "center", padding: "9px 10px", borderRadius: 10, marginBottom: 5, color: C_INV.txt, background: on ? C_INV.cyanSoft : C_INV.panel2, border: `1px solid ${on ? C_INV.cyan + "55" : C_INV.line}` }}>
                      <span className="tnum" style={{ fontSize: 11, color: C_INV.sub }}>{ln.stt}</span>
                      <span className="tnum" style={{ fontSize: 11.5 }}>{ln.no || "—"}</span>
                      <span style={{ fontSize: 12, fontWeight: 600, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{ln.buyer || t("inv.noname")}</span>
                      <span className="tnum" style={{ textAlign: "right", fontSize: 12, fontWeight: 700, color: C_INV.green }}>{fmtTr_INV(ln.total)}</span>
                      <span className="tnum" style={{ textAlign: "right", fontSize: 11.5, color: C_INV.violet }}>{ln.vatRate ? ln.vatRate + "%" : "—"}</span>
                      <span style={{ textAlign: "center" }}>{warns ? <span className="tnum" style={{ fontSize: 10.5, fontWeight: 800, color: C_INV.orange, background: C_INV.orangeSoft, padding: "2px 7px", borderRadius: 5 }}>{warns}</span> : <Check size={14} color={C_INV.green} style={{ verticalAlign: "middle" }} />}</span>
                    </button>
                  ); })}
                  <div style={{ display: "grid", gridTemplateColumns: "30px 70px minmax(0,1.6fr) 84px 90px 70px", gap: 8, padding: "9px 10px", borderTop: `2px solid ${C_INV.line}`, marginTop: 3 }}>
                    <span></span><span></span><span style={{ fontSize: 11.5, fontWeight: 700, color: C_INV.sub }}>{t("inv.sumrow")}</span>
                    <span className="tnum" style={{ textAlign: "right", fontSize: 12.5, fontWeight: 800, color: C_INV.green }}>{fmtTr_INV(totals.total)}</span>
                    <span></span><span></span>
                  </div>
                </div></div>
              </section>

              {/* RIGHT: detail of selected invoice */}
              <section className="card" style={{ ...panelInv, opacity: done("ocr") ? 1 : .4, transition: "opacity .4s" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}><Tag size={17} color={C_INV.gold} /><h3 style={h3Inv}>{t("inv.detail.title", { no: cur.no || cur.stt })}</h3></div>
                <div style={{ fontSize: 11.5, color: C_INV.sub, marginBottom: 11 }}>{cur.item} · {cur.buyer || t("inv.noname")} · {cur.date}</div>

                {/* journal entries */}
                <div style={{ display: "flex", flexDirection: "column", gap: 7, opacity: done("cls") ? 1 : .3, transition: "opacity .4s" }}>
                  {classify_INV(cur).map((r, i) => (
                    <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "9px 12px", borderRadius: 10, background: C_INV.panel2, border: `1px solid ${C_INV.line}` }}>
                      <span className="tnum" style={{ fontSize: 15, fontWeight: 800, color: r.c, width: 42 }}>{r.acc}</span>
                      <span style={{ fontSize: 9.5, fontWeight: 800, color: r.side === "Nợ" ? C_INV.cyan : C_INV.orange, background: (r.side === "Nợ" ? C_INV.cyan : C_INV.orange) + "1f", padding: "2px 7px", borderRadius: 6, width: 32, textAlign: "center" }}>{r.side === "Nợ" ? t("inv.side.no") : t("inv.side.co")}</span>
                      <span style={{ flex: 1, minWidth: 0, fontSize: 12, fontWeight: 600, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{r.name}</span>
                      <span className="tnum" style={{ fontSize: 12.5, fontWeight: 700 }}>{fmtVnd_INV(r.amount)}</span>
                    </div>
                  ))}
                </div>

                {/* checks */}
                <div style={{ marginTop: 12, display: "grid", gap: 6, opacity: done("chk") ? 1 : .3, transition: "opacity .4s" }}>
                  {checkLine_INV(cur).map((c, i) => (
                    <div key={i} style={{ display: "flex", gap: 9, alignItems: "center", padding: "8px 11px", borderRadius: 9, background: c.ok ? C_INV.greenSoft : C_INV.orangeSoft, border: `1px solid ${(c.ok ? C_INV.green : C_INV.orange)}33` }}>
                      {c.ok ? <CheckCircle2 size={14} color={C_INV.green} style={{ flex: "0 0 auto" }} /> : <AlertTriangle size={14} color={C_INV.orange} style={{ flex: "0 0 auto" }} />}
                      <span style={{ fontSize: 11.8, fontWeight: 600, flex: 1 }}>{c.label}</span>
                      <span className="tnum" style={{ fontSize: 11, color: C_INV.sub }}>{c.v}</span>
                    </div>
                  ))}
                </div>
              </section>
            </div>

            {/* CASHFLOW INTEGRATION */}
            <section className="card" style={{ ...panelInv, marginTop: 16, opacity: done("cash") ? 1 : .4, transition: "opacity .4s", borderColor: done("cash") ? C_INV.green + "44" : C_INV.line }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", marginBottom: 4 }}>
                <TrendingUp size={17} color={C_INV.green} /><h3 style={h3Inv}>{t("inv.cash.title")}</h3>
                {done("cash") && <span style={{ marginLeft: "auto", display: "inline-flex", alignItems: "center", gap: 5, fontSize: 10.5, fontWeight: 800, color: C_INV.green, background: C_INV.greenSoft, padding: "3px 9px", borderRadius: 20 }}><CheckCircle2 size={12} />{t("inv.cash.merged", { n: lines.length })}</span>}
              </div>
              {cf ? (
                <>
                  <div style={{ fontSize: 12, color: C_INV.sub, marginBottom: 10 }}>{t("inv.cash.spread", { v: fmtTr_INV(totals.total) })}</div>
                  <div style={{ display: "grid", gap: 10, gridTemplateColumns: "repeat(auto-fit,minmax(185px,1fr))", marginBottom: 12 }}>
                    <Mini2Inv label={t("inv.cash.minBase")} v={fmtTr_INV(cf.minBase)} c={cf.minBase < 0 ? C_INV.red : C_INV.orange} sub={cf.firstNegBase >= 0 ? t("inv.cash.negFrom", { w: cf.firstNegBase + 1 }) : t("inv.cash.noNeg")} />
                    <Mini2Inv label={t("inv.cash.minRecv")} v={fmtTr_INV(cf.minRecv)} c={cf.minRecv < 0 ? C_INV.red : C_INV.green} sub={cf.firstNegRecv >= 0 ? t("inv.cash.negFrom", { w: cf.firstNegRecv + 1 }) : t("inv.cash.noNegAll")} />
                    <Mini2Inv label={t("inv.cash.improve")} v={"+" + fmtTr_INV(cf.minRecv - cf.minBase)} c={C_INV.cyan} sub={t("inv.cash.thanksTo", { v: fmtTr_INV(totals.total) })} />
                  </div>
                  <div style={{ height: 300, marginLeft: -10 }}>
                    <ResponsiveContainer width="100%" height="100%">
                      <ComposedChart data={cf.data} margin={{ top: 8, right: 12, bottom: 4, left: 4 }}>
                        <defs><linearGradient id="gRecvInv" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={C_INV.green} stopOpacity={0.26} /><stop offset="100%" stopColor={C_INV.green} stopOpacity={0.04} /></linearGradient></defs>
                        <CartesianGrid stroke={C_INV.line2} vertical={false} />
                        <XAxis dataKey="name" tick={{ fill: C_INV.sub, fontSize: 11.5, fontFamily: MONO_INV }} axisLine={{ stroke: C_INV.line }} tickLine={false} />
                        <YAxis tickFormatter={(v) => Math.round(v).toLocaleString("vi-VN")} tick={{ fill: C_INV.sub, fontSize: 11.5, fontFamily: MONO_INV }} axisLine={false} tickLine={false} width={48} />
                        <Tooltip content={<CashTipInv />} cursor={{ stroke: C_INV.line }} />
                        <ReferenceLine y={0} stroke={C_INV.red} strokeWidth={1.4} strokeDasharray="2 3" />
                        <Area type="monotone" dataKey="recv" stroke={C_INV.green} strokeWidth={2.8} fill="url(#gRecvInv)" dot={false} activeDot={{ r: 4, fill: C_INV.green }} animationDuration={600} />
                        <Line type="monotone" dataKey="base" stroke={C_INV.sub} strokeWidth={1.7} strokeDasharray="5 4" dot={false} animationDuration={600} />
                      </ComposedChart>
                    </ResponsiveContainer>
                  </div>
                  <div style={{ display: "flex", gap: 16, fontSize: 12, color: C_INV.sub, marginTop: 8, flexWrap: "wrap" }}>
                    <LgInv c={C_INV.green} label={t("inv.cash.after")} />
                    <LgInv c={C_INV.sub} dash label={t("inv.cash.before")} />
                  </div>
                </>
              ) : (
                <div style={{ padding: "26px 14px", textAlign: "center", color: C_INV.sub, fontSize: 13 }}>{t("inv.cash.running")}</div>
              )}
            </section>
          </>
        )}

        <footer style={{ marginTop: 18, fontSize: 11.5, color: C_INV.sub, textAlign: "center", lineHeight: 1.6 }}>
          {t("inv.footer")}
        </footer>
      </div>
    </div>
  );
}

/* ---------- sub components ---------- */
const panelInv = { background: C_INV.panel, border: `1px solid ${C_INV.line}`, borderRadius: 18, padding: "16px 18px 16px", boxShadow: "0 18px 40px -28px rgba(0,0,0,.7)" };
const h3Inv = { margin: 0, fontFamily: DISP_INV, fontWeight: 700, fontSize: 15.5, letterSpacing: "-0.01em", color: C_INV.txt };
function KpiInv({ label, v, c, icon }) {
  return (<div className="card" style={{ ...panelInv, padding: "14px 15px" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}><span style={{ fontSize: 11.8, color: C_INV.sub, fontWeight: 600 }}>{label}</span><span style={{ color: c }}>{icon}</span></div><div className="tnum" style={{ fontSize: 19, fontWeight: 800, color: c, letterSpacing: "-0.02em" }}>{v}</div></div>);
}
function Mini2Inv({ label, v, c, sub }) {
  return (<div style={{ padding: "11px 13px", borderRadius: 11, background: C_INV.panel2, border: `1px solid ${C_INV.line}` }}><div style={{ fontSize: 11, color: C_INV.sub, fontWeight: 600 }}>{label}</div><div className="tnum" style={{ fontSize: 18, fontWeight: 800, color: c, marginTop: 3 }}>{v}</div><div style={{ fontSize: 10.5, color: C_INV.sub, marginTop: 2 }}>{sub}</div></div>);
}
function LgInv({ c, label, dash }) { return <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}><span style={{ width: 18, borderTop: `${dash ? "2px dashed" : "3px solid"} ${c}` }} />{label}</span>; }
function CashTipInv({ active, payload }) {
  const { t } = useT();
  if (!active || !payload || !payload.length) return null; const d = payload[0].payload;
  return (
    <div style={{ background: "#0A0F1C", border: `1px solid ${C_INV.line}`, borderRadius: 12, padding: "11px 13px", fontFamily: UI_INV, boxShadow: "0 14px 30px rgba(0,0,0,.5)", minWidth: 190 }}>
      <div style={{ fontWeight: 800, fontSize: 13 }}>{t("inv.chart.week")} {d.idx + 1} <span style={{ color: C_INV.sub, fontWeight: 500 }}>· {d.range}</span></div>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 18, fontSize: 12, marginTop: 6 }}><span style={{ color: C_INV.sub }}>{t("inv.tip.after")}</span><span className="tnum" style={{ color: d.recv < 0 ? C_INV.red : C_INV.green, fontWeight: 700 }}>{d.recv.toLocaleString("vi-VN")} tr</span></div>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 18, fontSize: 12, marginTop: 4 }}><span style={{ color: C_INV.sub }}>{t("inv.tip.before")}</span><span className="tnum" style={{ color: d.base < 0 ? C_INV.red : C_INV.sub, fontWeight: 700 }}>{d.base.toLocaleString("vi-VN")} tr</span></div>
      {d.collect > 0 && <div style={{ fontSize: 11, color: C_INV.green, marginTop: 6 }}>★ {t("inv.tip.collect")} +{d.collect.toLocaleString("vi-VN")} tr</div>}
    </div>
  );
}

